(335, NULL, 'Thomas Walker', 'thomas.walker@jmailservice.com', NULL, '8054002077', 'Imagine your brand appearing first when customers search online. That\'s exactly what we do - and we can launch it within a day.\r\nCan I show you how it looks?', NULL, NULL, '2026-02-01 11:15:27', '2026-02-01 11:15:27'),
(336, NULL, 'Joanna Riggs', 'joannariggs278@gmail.com', NULL, '6211360868', 'Hi,\r\n\r\nI just visited bayyinahtravels.com and wondered if you\'ve ever considered an impactful video to advertise your business? Our videos can generate impressive results on both your website and across social media.\r\n\r\nOur videos cost just $195 (USD) for a 30 second video ($239 for 60 seconds) and include a full script, voice-over and video.\r\n\r\nI can show you some previous videos we\'ve done if you want me to send some over. Let me know if you\'re interested in seeing samples of our previous work.\r\n\r\nRegards,\r\nJoanna\r\n\r\nUnsubscribe: https://unsubscribe.video/unsubscribe.php?d=bayyinahtravels.com', NULL, NULL, '2026-02-05 11:36:19', '2026-02-05 11:36:19'),
(337, NULL, 'jwgIiMqDIqgEERYk', 'c.e.leme.pew.a.00@gmail.com', NULL, 'ApTnrrkuAdcibBNmmrfaI', 'cJmWoPKygYJlhNSXAt', NULL, NULL, '2026-02-05 22:01:36', '2026-02-05 22:01:36'),
(338, NULL, 'Lavina Curtis', 'lavina.curtis@gmail.com', NULL, '81672358', 'If YouŌĆÖre Still Asking for Reviews ManuallyŌĆ” YouŌĆÖre Already Behind A single negative review can push customers to your competitors. MaxReviewFlow fixes the followŌĆæup problem with automated reminders, smart filtering, and realŌĆætime reporting. Dominate your local market with the reputation you deserve. Take back the top spot with MaxReviewFlow.com', NULL, NULL, '2026-02-06 01:52:44', '2026-02-06 01:52:44');
INSERT INTO `contact_us` (`id`, `package_id`, `full_name`, `email`, `subject`, `number`, `message`, `addedBy_id`, `editedBy_id`, `created_at`, `updated_at`) VALUES
(339, NULL, 'Nathaniel Brooks', 'nathaniel.reid@jmailservice.com', NULL, '8054002077', 'We can position your brand above competitors within 24 hours - no waiting, no complicated setup.\r\nWould you like to see a sample?', NULL, NULL, '2026-02-09 22:35:34', '2026-02-09 22:35:34'),
(340, NULL, 'Verlene Slagle', 'slagle.verlene@gmail.com', NULL, '691321662', 'Skyrocket bayyinahtravels.com rankings, expand your online exposure and generate powerful backlinks! \r\nBonusBacklinks.com - we provide daily backlinks and bring organic visits to your site EVERY DAY: \r\n\r\nUse 85% OFF \r\nQuality daily seo backlinks \r\nOrganic website traffic \r\nPrice cheap as $1 \r\nBonus discount codes: \r\n\r\nhttps://BonusBacklinks.com/85save\r\n\r\nBonusBacklinks.com - daily backlinks and website traffic to grow your webpage every day', NULL, NULL, '2026-02-13 20:05:51', '2026-02-13 20:05:51'),
(341, NULL, 'Patrick Donovan', 'patrick.donovan@jmailservice.com', NULL, '8054002077', 'SEO takes time. PPC gets expensive. Social ads interrupt people.\r\n\r\nWe do something different.\r\n\r\nWe put your brand directly in front of people actively searching for the keywords you choose. Setup takes less than a day and traffic is guaranteed.\r\n\r\nIf you\'d like details, send:\r\n - Your website\r\n - The keywords you want to target\r\n\r\nI\'ll check availability and send projected traffic numbers.\r\n\r\nLooking forward to your reply.', NULL, NULL, '2026-03-04 22:24:55', '2026-03-04 22:24:55'),
(342, NULL, 'Jayrn Smith', 'vail.zandra@gmail.com', NULL, '98384934', 'Hi, itŌĆÖs Jayrn.\r\n\r\nYou are about to master Magnetic MarketingŌĆöthe system where customers hunt you down, and you never have to ŌĆ£get slappedŌĆØ by the exhaustion of cold prospecting again. \r\n\r\nThis methodology is built upon Dan KennedyŌĆÖs 34-year proven ŌĆ£Magnetic MarketingŌĆØ systemŌĆöa strategic machine that has generated over $65 million in sales across 200 different niches. \r\n\r\nThe final result is a business that operates in a ŌĆ£competitive vacuum,ŌĆØ insulating you from price-shopping and the sting of rejection. \r\n\r\nHowever, before you can add new strategies, you must perform an aggressive removal of the strategic waste and ŌĆ£excess equipmentŌĆØ currently sabotaging your growth.\r\n\r\nLearn More: https://marketersmentor.com/attracting-buyers.php?refer=bayyinahtravels.com\r\n\r\nJayrn\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\nUnsubscribe: \r\nhttps://marketersmentor.com/unsubscribe.php?d=bayyinahtravels.com', NULL, NULL, '2026-03-08 16:08:15', '2026-03-08 16:08:15'),
(343, NULL, 'Jonathan Pierce', 'jonathan.pierce@jmailservice.com', NULL, '8054002077', 'This will be my last email.\r\n\r\nIf dominating your top search terms matters to you, now is the time to act.\r\n\r\nWe:\r\n\r\nGuarantee traffic in writing\r\n\r\nTrack everything in your analytics\r\n\r\nAllow keyword swaps at no charge\r\n\r\nGo live within 24 hours\r\n\r\nIf you want in, send:\r\n - Your website\r\n - Your keyword list\r\n\r\nI\'ll prioritize your review and send the numbers immediately.\r\n\r\nOtherwise, I\'ll close your file.', NULL, NULL, '2026-03-12 19:34:37', '2026-03-12 19:34:37'),
(344, NULL, 'MD HASAN MURSHED', 'hmurshed66@gmail.com', NULL, '+966-504561485', 'I am living in Madinah', NULL, NULL, '2026-03-15 08:34:14', '2026-03-15 08:34:14'),
