(6, 26, '{\"en\":\"Our mission\",\"bn\":null}', '{\"en\":\"<p class=\\\"w3-large\\\">Our mission is not just to meet expectations but to exceed them, creating lasting value for our clients and making a positive impact in their life<\\/p><p class=\\\"w3-large\\\">At Umarh, we believe that our success is measured by the satisfaction and success of our clients. We are dedicated to building long-term relationships based on trust, quality, and mutual respect.<\\/p>\",\"bn\":null}', 1, 1, 3, 3, '2024-08-20 12:18:00', '2024-08-20 12:20:31'),
(7, 27, '{\"en\":\"Our Services 1st part\",\"bn\":null}', '{\"en\":\"<p class=\\\"w3-large\\\">Our services are crafted with the pilgrim in mind, ensuring that every detail, from travel arrangements, accommodation to worship, is handled with the utmost care and professionalism. We offer packages while maintaining the highest standards of quality and service. Your trusted partner in making your Umrah experience truly unforgettable.<br><\\/p>\",\"bn\":null}', 1, 1, 3, 3, '2024-08-20 12:22:32', '2024-08-20 12:22:49');
