INSERT INTO `question_answers` (`id`, `question`, `answer`, `active`, `drag_id`, `addedBy_id`, `editedBy_id`, `created_at`, `updated_at`) VALUES
(1, '{\"bn\": \"Ó”ōÓ”«Ó”░Ó”ŠÓ”╣ Ó”ĢÓ”┐?\", \"en\": \"What is the Umrah?\"}', '{\"bn\": \"Ó”ōÓ”«Ó”░Ó”ŠÓ”╣ Ó”╣Ó”▓ Ó”ćÓ”╣Ó”░Ó”ŠÓ”« Ó”ģÓ”¼Ó”ĖÓ¦ŹÓ”źÓ”ŠÓ”»Ó”╝ Ó”¬Ó¦ŹÓ”░Ó”¼Ó¦ćÓ”Č Ó”ĢÓ”░Ó¦ć, Ó”śÓ”░Ó¦ćÓ”░ Ó”¬Ó¦ŹÓ”░Ó””Ó”ĢÓ¦ŹÓ”ĘÓ”┐Ó”Ż Ó”ĢÓ”░Ó¦ć, Ó”ĖÓ”ŠÓ”½Ó”Š Ó”ō Ó”«Ó”ŠÓ”░Ó”ōÓ”»Ó”╝Ó”ŠÓ”░ Ó”«Ó”¦Ó¦ŹÓ”»Ó¦ć Ó””Ó¦īÓ”ĪÓ”╝Ó”ŠÓ”©Ó¦ŗ Ó”ÅÓ”¼Ó”é Ó”«Ó”ŠÓ”źÓ”Š Ó”«Ó¦üÓ”ŻÓ¦ŹÓ”ĪÓ”© Ó”¼Ó”Š Ó”øÓ”ŠÓ”üÓ”¤Ó”ŠÓ”ć Ó”ĢÓ”░Ó¦ć Ó”åÓ”▓Ó¦ŹÓ”▓Ó”ŠÓ”╣Ó”░ Ó”ćÓ”¼Ó”ŠÓ””Ó”ż Ó”ĢÓ”░Ó”ŠÓźż\", \"en\": \"Umrah is an act of worshipping Allah by entering the state of Ihram, circumambulating the House, running between Safa and Marwa, and having the head shaved or trimmed.\"}', 1, 1, 1, NULL, '2024-03-13 08:39:19', '2024-03-13 08:39:19'),
(2, '{\"bn\": \"Ó”åÓ”«Ó”┐ Ó”ĢÓ”┐Ó”ŁÓ”ŠÓ”¼Ó¦ć Ó”ćÓ”╣Ó”░Ó”ŠÓ”« Ó”ģÓ”¼Ó”ĖÓ¦ŹÓ”źÓ”ŠÓ”»Ó”╝ Ó”¬Ó¦ŹÓ”░Ó”¼Ó¦ćÓ”Č Ó”ĢÓ”░Ó”¼?\", \"en\": \"How do I enter into the state of Ihram?\"}', '{\"bn\": \"Ó”ÅÓ”ĢÓ”£Ó”© Ó”«Ó¦üÓ”ĖÓ”▓Ó”«Ó”ŠÓ”© Ó”ČÓ”░Ó”┐Ó”»Ó”╝Ó”Š Ó””Ó¦ŹÓ”¼Ó”ŠÓ”░Ó”Š Ó”©Ó”┐Ó”░Ó¦ŹÓ””Ó”┐Ó”ĘÓ¦ŹÓ”¤ Ó”ĖÓ¦ŹÓ”źÓ”ŠÓ”©Ó¦ć Ó”ćÓ”╣Ó”░Ó”ŠÓ”« Ó”ģÓ”¼Ó”ĖÓ¦ŹÓ”źÓ”ŠÓ”»Ó”╝ Ó”¬Ó¦ŹÓ”░Ó”¼Ó¦ćÓ”Č Ó”ĢÓ”░Ó”¼Ó¦ć Ó”ÅÓ”¼Ó”é Ó”ćÓ”╣Ó”░Ó”ŠÓ”«Ó¦ćÓ”░ Ó”©Ó”┐Ó”ĘÓ¦ćÓ”¦Ó”ŠÓ”£Ó¦ŹÓ”×Ó”ŠÓ”ŚÓ¦üÓ”▓Ó”┐ Ó”źÓ¦ćÓ”ĢÓ¦ć Ó”¼Ó”┐Ó”░Ó”ż Ó”źÓ”ŠÓ”ĢÓ”¼Ó¦ćÓźż\\r\\nÓ”żÓ”┐Ó”©Ó”┐ Ó”żÓ”ŠÓ”▓Ó”¼Ó”┐Ó”»Ó”╝Ó”Š Ó”¬Ó”ŠÓ”Ā Ó”ĢÓ”░Ó”¼Ó¦ćÓ”© Ó”ÅÓ”ć Ó”¼Ó”▓Ó¦ć: \\\"Ó”▓Ó”ŠÓ”¼Ó¦ŹÓ”¼Ó”ŠÓ”ćÓ”ĢÓ”Š Ó”åÓ”▓Ó¦ŹÓ”▓Ó”ŠÓ”╣Ó¦üÓ”«Ó¦ŹÓ”«Ó”Š Ó”▓Ó”ŠÓ”¼Ó¦ŹÓ”¼Ó”ŠÓ”ćÓ”Ģ, Ó”▓Ó”ŠÓ”¼Ó¦ŹÓ”¼Ó”ŠÓ”ćÓ”ĢÓ”Š Ó”▓Ó”Š Ó”ČÓ”░Ó¦ĆÓ”ĢÓ”Š Ó”▓Ó”ŠÓ”ĢÓ”Š Ó”▓Ó”ŠÓ”¼Ó¦ŹÓ”¼Ó”ŠÓ”ćÓ”ĢÓźż Ó”ćÓ”©Ó¦ŹÓ”©Ó”ŠÓ”▓ Ó”╣Ó”ŠÓ”«Ó””Ó”Š Ó”ōÓ”»Ó”╝Ó”ŠÓ”©-Ó”©Ó”┐\'Ó”«Ó”ŠÓ”żÓ”Š Ó”▓Ó”ŠÓ”ĢÓ”Š Ó”ōÓ”»Ó”╝Ó”ŠÓ”▓-Ó”«Ó¦üÓ”▓Ó”Ģ, Ó”▓Ó”Š Ó”ČÓ”░Ó¦ĆÓ”ĢÓ”Š Ó”▓Ó”ŠÓ”Ģ\\\" (Ó”╣Ó¦ć Ó”åÓ”▓Ó¦ŹÓ”▓Ó”ŠÓ”╣, Ó”åÓ”«Ó”┐ Ó”åÓ”¬Ó”©Ó”ŠÓ”░ Ó”¢Ó¦ćÓ””Ó”«Ó”żÓ¦ć Ó”åÓ”øÓ”┐! Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░ Ó”ĖÓ¦ćÓ”¼Ó”Š! Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░ Ó”ĢÓ¦ŗÓ”©Ó¦ŗ Ó”ģÓ”éÓ”ČÓ¦ĆÓ””Ó”ŠÓ”░ Ó”©Ó¦ćÓ”ć! Ó”åÓ”«Ó”┐ Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░ Ó”ĖÓ¦ćÓ”¼Ó”ŠÓ”»Ó”╝ Ó”©Ó”┐Ó”»Ó”╝Ó¦ŗÓ”£Ó”┐Ó”ż! Ó”¬Ó¦ŹÓ”░Ó”ĢÓ¦āÓ”żÓ”¬Ó”ĢÓ¦ŹÓ”ĘÓ¦ć, Ó”ĖÓ”«Ó”ĖÓ¦ŹÓ”ż Ó”¬Ó¦ŹÓ”░Ó”ČÓ”éÓ”ĖÓ”Š Ó”ō Ó”ĢÓ”░Ó¦üÓ”ŻÓ”Š Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░Ó”ć, Ó”ÅÓ”¼Ó”é Ó”ĖÓ”░Ó¦ŹÓ”¼Ó¦ŗÓ”ÜÓ¦ŹÓ”Ü Ó”ĢÓ”░Ó¦ŹÓ”żÓ¦āÓ”żÓ¦ŹÓ”¼Ó”ō Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░Óźż Ó”żÓ¦ŗÓ”«Ó”ŠÓ”░ Ó”ĢÓ¦ŗÓ”©Ó¦ŗ Ó”ģÓ”éÓ”ČÓ¦ĆÓ””Ó”ŠÓ”░ Ó”©Ó¦ćÓ”ć)\", \"en\": \"A Muslim enters into the state of Ihram at the place specified by Sharia, and shall abstain from the Ihram prohibitions.\\r\\nHe shall recite Talbiyah, saying: \\\"Labbayka Allaahumma Labbayk, Labbayka La Shareeka Laka Labbayk. Innal Hamda Wan-ni\'mata Laka Wal-Mulk, La Shareeka Lak\\\" (Here I am at your service, o Allah, at Your service! At Your service! You have no partner! I am at Your service! Indeed, all praise and grace belong to You, and so does the supreme authority. You have no partner)\"}', 1, 2, 1, NULL, '2024-03-13 08:45:29', '2024-03-13 08:45:29'),
(3, '{\"bn\": \"Ó”ōÓ”«Ó”░Ó”ŠÓ”╣ Ó”ÅÓ”¼Ó”é Ó”╣Ó”£Ó¦ŹÓ”£Ó¦ćÓ”░ Ó”«Ó”¦Ó¦ŹÓ”»Ó¦ć Ó”¬Ó”ŠÓ”░Ó¦ŹÓ”źÓ”ĢÓ¦ŹÓ”» Ó”ĢÓ”┐?\", \"en\": \"What is the difference between Umrah and Hajj?\"}', '{\"bn\": \"Ó”ōÓ”«Ó”░Ó”ŠÓ”╣ Ó”¼Ó”øÓ”░Ó¦ćÓ”░ Ó”»Ó¦ć Ó”ĢÓ¦ŗÓ”©Ó¦ŗ Ó”ĖÓ”«Ó”»Ó”╝Ó¦ć Ó”ĢÓ”░Ó”Š Ó”»Ó¦ćÓ”żÓ¦ć Ó”¬Ó”ŠÓ”░Ó¦ć, Ó”żÓ”¼Ó¦ć Ó”╣Ó”£ Ó”¬Ó¦ŹÓ”░Ó”żÓ”┐ Ó”¼Ó”øÓ”░ Ó”£Ó¦üÓ”▓-Ó”╣Ó”┐Ó”£Ó¦ŹÓ”£Ó”ŠÓ”╣ Ó”«Ó”ŠÓ”ĖÓ¦ć Ó”ĢÓ”░Ó”Š Ó”ēÓ”ÜÓ”┐Ó”żÓźż\", \"en\": \"Umrah may be performed at any time of the year, but Hajj should be performed during the month of Dhu\'l-Hijjah every year.\"}', 1, 3, 1, NULL, '2024-03-13 08:47:18', '2024-03-13 08:47:18'),
(4, '{\"bn\": \"Ó”ĢÓ¦ć Ó”╣Ó”£ Ó”ĢÓ”░Ó”żÓ¦ć Ó”¬Ó”ŠÓ”░Ó”¼Ó¦ć?\", \"en\": \"Who can perform Hajj?\"}', '{\"bn\": \"Ó”ÅÓ”ĢÓ”£Ó”© Ó”¬Ó¦ŹÓ”░Ó”ŠÓ”¬Ó¦ŹÓ”żÓ”¼Ó”»Ó”╝Ó”ĖÓ¦ŹÓ”Ģ Ó”«Ó¦üÓ”ĖÓ”▓Ó”«Ó”ŠÓ”© Ó”¼Ó”┐Ó”ČÓ¦üÓ””Ó¦ŹÓ”¦ Ó”«Ó”©, Ó”ĖÓ”ĢÓ¦ŹÓ”ĘÓ”« Ó”ČÓ”░Ó¦ĆÓ”░ Ó”ÅÓ”¼Ó”é Ó”¢Ó”░Ó”Ü Ó”¼Ó”╣Ó”© Ó”ĢÓ”░Ó”ŠÓ”░ Ó”ĢÓ¦ŹÓ”ĘÓ”«Ó”żÓ”ŠÓ”ĖÓ”«Ó¦ŹÓ”¬Ó”©Ó¦ŹÓ”© Ó”¼Ó¦ŹÓ”»Ó”ĢÓ¦ŹÓ”żÓ”┐Ó”ĢÓ¦ć Ó”żÓ”ŠÓ”░ Ó”£Ó¦ĆÓ”¼Ó”©Ó¦ć Ó”ÅÓ”ĢÓ”¼Ó”ŠÓ”░ Ó”╣Ó”£ Ó”ĢÓ”░Ó”żÓ¦ć Ó”╣Ó”¼Ó¦ćÓźż Ó”ČÓ”┐Ó”ČÓ¦ü, Ó”ģÓ”ĖÓ¦üÓ”ĖÓ¦ŹÓ”ź Ó”ÅÓ”¼Ó”é Ó”»Ó”ŠÓ”░Ó”Š Ó”¢Ó”░Ó”Ü Ó”¼Ó”╣Ó”© Ó”ĢÓ”░Ó”żÓ¦ć Ó”¬Ó”ŠÓ”░Ó¦ć Ó”©Ó”Š Ó”żÓ”ŠÓ””Ó¦ćÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”╣Ó”£ Ó”½Ó”░Ó”£ Ó”©Ó”»Ó”╝Óźż\", \"en\": \"An adult Muslim of a sane mind, an able body and having means to bear the expenses must perform Hajj once in his/her lifetime. Hajj is not obligatory for children, the sick, and those who cannot bear the costs.\"}', 1, 4, 1, NULL, '2024-03-13 08:48:19', '2024-03-13 08:48:19'),
(5, '{\"bn\": \"Ó”ĖÓ¦īÓ””Ó”┐ Ó”åÓ”░Ó”¼Ó¦ć Ó”åÓ”«Ó”ŠÓ”░ Ó”ĖÓ”ŠÓ”źÓ¦ć Ó”ĢÓ”┐ Ó”¦Ó”░Ó”©Ó¦ćÓ”░ Ó”¬Ó¦ŗÓ”ČÓ”ŠÓ”Ģ Ó”ÅÓ”¼Ó”é Ó”¼Ó”┐Ó”øÓ”ŠÓ”©Ó”ŠÓ”¬Ó”żÓ¦ŹÓ”░ Ó”©Ó”┐Ó”»Ó”╝Ó¦ć Ó”»Ó¦ćÓ”żÓ¦ć Ó”╣Ó”¼Ó¦ć?\", \"en\": \"What kinds of clothing and bedding should I take with me to Saudi Arabia?\"}', '{\"bn\": \"Ó”ģÓ”¬Ó”░Ó”┐Ó”╣Ó”ŠÓ”░Ó¦ŹÓ”» Ó”¼Ó”┐Ó”ĘÓ”»Ó”╝ Ó”╣Ó”▓ Ó””Ó¦üÓ”ć Ó”¼Ó”Š Ó”żÓ”┐Ó”© Ó”ĖÓ¦ćÓ”¤ Ó”ćÓ”╣Ó”░Ó”ŠÓ”«Óźż Ó”ćÓ”╣Ó”░Ó”ŠÓ”«Ó¦ć Ó”ĖÓ”ŠÓ””Ó”Š Ó”ĖÓ”ŠÓ””Ó”Š Ó”ĢÓ”ŠÓ”¬Ó”ĪÓ”╝Ó¦ćÓ”░ Ó””Ó¦üÓ”¤Ó”┐ Ó”¤Ó¦üÓ”ĢÓ”░Ó”Š Ó”źÓ”ŠÓ”ĢÓ¦ć, Ó”╣Ó”»Ó”╝ 100% Ó”ĖÓ¦üÓ”żÓ”┐ Ó”¼Ó”Š Ó”╣Ó”ŠÓ”▓Ó”ĢÓ”Š Ó”¤Ó¦ćÓ”░Ó”┐ Ó”ĢÓ”ŠÓ”¬Ó”ĪÓ”╝Óźż Ó”ÅÓ”ŚÓ¦üÓ”▓Ó”┐ Ó”¬Ó”░Ó”ŠÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”ČÓ¦ĆÓ”żÓ”▓ Ó”ÅÓ”¼Ó”é Ó”╣Ó”£Ó¦ćÓ”░ Ó”ĖÓ”«Ó”»Ó”╝ Ó”åÓ”¬Ó”©Ó”ŠÓ”░ Ó”ģÓ”©Ó”┐Ó”¼Ó”ŠÓ”░Ó¦ŹÓ”»Ó”ŁÓ”ŠÓ”¼Ó¦ć Ó”»Ó¦ć Ó”ŁÓ”ŠÓ”░Ó¦Ć Ó”śÓ”ŠÓ”«Ó¦ćÓ”░ Ó”ģÓ”ŁÓ”┐Ó”£Ó¦ŹÓ”×Ó”żÓ”Š Ó”╣Ó”¼Ó¦ć Ó”żÓ”Š Ó”åÓ”░Ó”ō Ó”ŁÓ”ŠÓ”▓ Ó”ČÓ¦ŗÓ”ĘÓ”ŻÓ¦ćÓ”░ Ó”£Ó”©Ó¦ŹÓ”»Ó”ō Ó”¬Ó¦ŹÓ”░Ó””Ó”ŠÓ”© Ó”ĢÓ”░Ó¦ćÓ¦Ę Ó”ÅÓ”øÓ”ŠÓ”ĪÓ”╝Ó”ŠÓ”ō Ó”░Ó”ŠÓ”ĖÓ¦ŹÓ”żÓ”ŠÓ”░ Ó”¬Ó”░Ó”┐Ó”¦Ó”ŠÓ”©Ó¦ćÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”åÓ”¬Ó”©Ó”ŠÓ”░ Ó”ĖÓ”ŠÓ”źÓ¦ć Ó”╣Ó”ŠÓ”▓Ó”ĢÓ”Š Ó”ÅÓ”¼Ó”é Ó”¼Ó”ŠÓ”żÓ”ŠÓ”ĖÓ”»Ó¦üÓ”ĢÓ¦ŹÓ”ż Ó”¬Ó¦ŗÓ”ČÓ”ŠÓ”Ģ Ó”©Ó”┐Ó”©Ó¦Ę Ó”åÓ”¬Ó”©Ó”ŠÓ”░ Ó”źÓ”ŠÓ”ĢÓ”ŠÓ”░ Ó”åÓ”░Ó”ŠÓ”«Ó””Ó”ŠÓ”»Ó”╝Ó”Ģ Ó”ĢÓ”░Ó”ŠÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”¬Ó”░Ó¦ŹÓ”»Ó”ŠÓ”¬Ó¦ŹÓ”ż Ó”¬Ó¦ŗÓ”ČÓ”ŠÓ”Ģ Ó”©Ó”┐Ó”©, Ó”żÓ”¼Ó¦ć Ó”ģÓ”¬Ó¦ŹÓ”░Ó”»Ó”╝Ó¦ŗÓ”£Ó”©Ó¦ĆÓ”»Ó”╝ Ó”ĢÓ”ŠÓ”¬Ó”ĪÓ”╝Ó¦ćÓ”░ Ó”ĖÓ”ŠÓ”źÓ¦ć Ó”©Ó”┐Ó”£Ó¦ćÓ”ĢÓ¦ć Ó”ģÓ”żÓ”┐Ó”░Ó”┐Ó”ĢÓ¦ŹÓ”ż Ó”¼Ó¦ŗÓ”ØÓ”ŠÓ”¼Ó¦ćÓ”© Ó”©Ó”ŠÓźż Ó”ĖÓ¦īÓ””Ó”┐ Ó”åÓ”░Ó”¼Ó¦ć Ó”¬Ó¦ćÓ”ČÓ”ŠÓ””Ó”ŠÓ”░ Ó”▓Ó”©Ó¦ŹÓ”ĪÓ¦ŹÓ”░Ó”┐ Ó”ĖÓ¦üÓ”¼Ó”┐Ó”¦Ó”Š Ó”¬Ó”ŠÓ”ōÓ”»Ó”╝Ó”Š Ó”»Ó”ŠÓ”»Ó”╝Óźż Ó”ČÓ¦ĆÓ”żÓ¦ćÓ”░ Ó”«Ó”ŠÓ”ĖÓ¦ć Ó”╣Ó”£Ó¦ć Ó”ŚÓ¦ćÓ”▓Ó¦ć Ó”ĢÓ”┐Ó”øÓ¦ü Ó”¬Ó”ČÓ”«Ó¦Ć Ó”¬Ó¦ŗÓ”ČÓ”ŠÓ”Ģ Ó”©Ó”┐Ó”© Ó”ĢÓ”ŠÓ”░Ó”Ż Ó”ĖÓ”ĢÓ”ŠÓ”▓Ó¦ćÓ”░ Ó”ĖÓ”ĢÓ”ŠÓ”▓Ó”¤Ó”Š Ó”ČÓ¦ĆÓ”żÓ”▓ Ó”źÓ”ŠÓ”ĢÓ¦ćÓźż Ó”ćÓ”╣Ó”░Ó”ŠÓ”«Ó¦ćÓ”░ Ó”ĖÓ”«Ó”»Ó”╝ Ó”¼Ó¦ŹÓ”»Ó”¼Ó”╣Ó”ŠÓ”░ Ó”ĢÓ”░Ó”ŠÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”żÓ”┐Ó”© Ó”¼Ó”Š Ó”ÜÓ”ŠÓ”░ Ó”£Ó¦ŗÓ”ĪÓ”╝Ó”Š Ó”░Ó”ŠÓ”¼Ó”ŠÓ”░Ó¦ćÓ”░ Ó”ÜÓ”¬Ó¦ŹÓ”¬Ó”▓ Ó”ÅÓ”¼Ó”é Ó”╣Ó”ŠÓ”üÓ”¤Ó”ŠÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó””Ó¦üÓ”ć Ó”£Ó¦ŗÓ”ĪÓ”╝Ó”Š Ó”åÓ”░Ó”ŠÓ”«Ó””Ó”ŠÓ”»Ó”╝Ó”Ģ Ó”£Ó¦üÓ”żÓ”Š Ó”¼Ó”Š Ó”ĖÓ¦ŹÓ”»Ó”ŠÓ”©Ó¦ŹÓ”ĪÓ¦ćÓ”▓Ó”ō Ó”©Ó”┐Ó”©Óźż Ó”ÅÓ”øÓ”ŠÓ”ĪÓ”╝Ó”ŠÓ”ō Ó””Ó¦üÓ”¤Ó”┐ Ó”¼Ó”ĪÓ”╝ Ó”ÅÓ”¼Ó”é Ó””Ó¦üÓ”¤Ó”┐ Ó”øÓ¦ŗÓ”¤ Ó”żÓ¦ŗÓ”»Ó”╝Ó”ŠÓ”▓Ó¦ć Ó”©Ó”┐Ó”©Ó¦Ę Ó”¼Ó”┐Ó”øÓ”ŠÓ”©Ó”ŠÓ”░ Ó”£Ó”©Ó¦ŹÓ”» Ó”åÓ”¬Ó”©Ó”ŠÓ”░ Ó”ĖÓ¦ŹÓ”▓Ó”┐Ó”¬Ó”┐Ó”é Ó”¼Ó¦ŹÓ”»Ó”ŠÓ”Ś, Ó”ÅÓ”ĢÓ”¤Ó”┐ Ó”ĖÓ¦ŹÓ”½Ó¦ĆÓ”ż Ó”¼Ó”ŠÓ”▓Ó”┐Ó”Č Ó”ÅÓ”¼Ó”é Ó”«Ó¦ŗÓ”¤Ó”Š Ó”ÜÓ”ŠÓ””Ó”░Ó¦ćÓ”░ Ó”¬Ó¦ŹÓ”░Ó”»Ó”╝Ó¦ŗÓ”£Ó”© Ó”╣Ó”żÓ¦ć Ó”¬Ó”ŠÓ”░Ó¦ćÓ¦Ę\", \"en\": \"The essential thing is two or three sets of Ihram. The Ihram consists of two pieces of white plain cloth, either 100% cotton or light terry-cloth. \\r\\nThese are cool to wear and also provide for better absorption of the heavy perspiration you will inevitably experience during Hajj.Also take with you light and airy clothes for street wear. Take enough clothes to make your stay comfortable, but do not over-burden yourself with unnecessary clothes. Professional laundry facilities are available in Saudi Arabia. If going on Hajj during winter months, take some woolen clothing as the early mornings tend to be cool.Take also three or four pairs of rubber slippers for use during Ihram, as well as couple of pairs of comfortable shoes or sandals for walking. Also take two large and two small towels.You may also need sleeping bag for bedding, an inflatable pillow and thick sheets.\"}', 1, 8, 1, NULL, '2024-03-13 08:50:11', '2024-03-13 08:50:11'),
(6, '{\"bn\": \"Ó”«Ó”ĢÓ¦ŹÓ”ĢÓ”Š Ó”ō Ó”«Ó””Ó¦ĆÓ”©Ó”ŠÓ”░ Ó”åÓ”¼Ó”╣Ó”ŠÓ”ōÓ”»Ó”╝Ó”Š Ó”ĢÓ¦ćÓ”«Ó”©?\", \"en\": \"What is the weather like in Makkah and Madinah?\"}', '{\"bn\": \"Ó”ŚÓ¦ŹÓ”░Ó¦ĆÓ”ĘÓ¦ŹÓ”«Ó¦ćÓ”░ Ó”«Ó”ŠÓ”ĖÓ”ŚÓ¦üÓ”▓Ó”┐Ó”żÓ¦ć Ó”ÅÓ”¤Ó”┐ Ó”¢Ó¦üÓ”¼ Ó”ŚÓ”░Ó”« Ó”źÓ”ŠÓ”ĢÓ¦ć, Ó””Ó”┐Ó”©Ó¦ćÓ”░ Ó”¼Ó¦ćÓ”▓Ó”Š Ó”żÓ”ŠÓ”¬Ó”«Ó”ŠÓ”żÓ¦ŹÓ”░Ó”Š 40 Ó”ĪÓ”┐Ó”ŚÓ¦ŹÓ”░Ó”┐ Ó”ĖÓ¦ćÓ”▓Ó”ĖÓ”┐Ó”»Ó”╝Ó”ŠÓ”Ė (100 Ó”ĪÓ”┐Ó”ŚÓ¦ŹÓ”░Ó”┐ Ó”½Ó”ŠÓ”░Ó¦ćÓ”©Ó”╣Ó”ŠÓ”ćÓ”¤) Ó”ÅÓ”░ Ó”ēÓ”¬Ó”░Ó¦ć Ó”¬Ó¦īÓ”üÓ”øÓ”ŠÓ”»Ó”╝Óźż Ó”ČÓ¦ĆÓ”żÓ¦ćÓ”░ Ó”ĖÓ”«Ó”»Ó”╝ Ó”åÓ”¼Ó”╣Ó”ŠÓ”ōÓ”»Ó”╝Ó”Š Ó”«Ó¦āÓ””Ó¦ü, Ó”żÓ”¼Ó¦ć Ó”ŁÓ¦ŗÓ”░Ó¦ć Ó”ÅÓ”¼Ó”é Ó”ŚÓ”ŁÓ¦ĆÓ”░ Ó”░Ó”ŠÓ”żÓ¦ć Ó”ĀÓ”ŠÓ”©Ó¦ŹÓ”ĪÓ”Š Ó”╣Ó”żÓ¦ć Ó”¬Ó”ŠÓ”░Ó¦ćÓźż\", \"en\": \"It is very hot during summer months, with temperature reaching upper 40┬░C (100┬░F) during day. During winter times the weather is mild, but early mornings and late nights could be cold.\"}', 1, 7, 1, NULL, '2024-03-13 08:57:43', '2024-03-13 08:57:43'),
(7, '{\"bn\": \"Ó”«Ó”ĢÓ¦ŹÓ”ĢÓ”Š Ó”ō Ó”«Ó””Ó¦ĆÓ”©Ó”ŠÓ”»Ó”╝ Ó”ĢÓ”┐ Ó”ĢÓ¦ŗÓ”© Ó”¼Ó¦ŹÓ”»Ó”ŠÓ”éÓ”Ģ Ó”åÓ”øÓ¦ć?\", \"en\": \"Are there any banks in Makkah and Madinah?\"}', '{\"bn\": \"Ó”«Ó”ĢÓ¦ŹÓ”ĢÓ”Š Ó”ō Ó”«Ó””Ó¦ĆÓ”©Ó”ŠÓ”»Ó”╝ Ó”ĢÓ”┐Ó”øÓ¦ü Ó”¼Ó”ĪÓ”╝ Ó”£Ó”ŠÓ”żÓ¦ĆÓ”»Ó”╝ Ó”ō Ó”åÓ”©Ó¦ŹÓ”żÓ”░Ó¦ŹÓ”£Ó”ŠÓ”żÓ”┐Ó”Ģ Ó”¼Ó¦ŹÓ”»Ó”ŠÓ”éÓ”ĢÓ¦ćÓ”░ Ó”ČÓ”ŠÓ”¢Ó”Š Ó”░Ó”»Ó”╝Ó¦ćÓ”øÓ¦ćÓźż\", \"en\": \"There are branches of some big national and international banks in Makkah and Madinah.\"}', 1, 6, 1, NULL, '2024-03-13 09:01:58', '2024-03-13 09:01:58'),
(8, '{\"bn\": \"Ó”¼Ó¦ŹÓ”»Ó”ŠÓ”éÓ”Ģ Ó”ĢÓ”┐ Ó”¼Ó¦łÓ””Ó¦ćÓ”ČÓ”┐Ó”Ģ Ó”«Ó¦üÓ””Ó¦ŹÓ”░Ó”Š Ó”¬Ó”░Ó”┐Ó”¼Ó”░Ó¦ŹÓ”żÓ”© Ó”ĢÓ”░Ó¦ć?\", \"en\": \"Do banks change foreign currency?\"}', '{\"bn\": \"Ó”╣Ó¦ŹÓ”»Ó”ŠÓ”ü\", \"en\": \"Yes\"}', 1, 5, 1, NULL, '2024-03-13 09:02:56', '2024-03-13 09:02:56');

